for item in doc.advances:
    if item.reference_type == "Payment Entry" and item.reference_name:
        pe = frappe.db.get_value(
            "Payment Entry",
            item.reference_name,
            ["reference_no", "reference_date"],
            as_dict=True
        ) or {}

        item.chequereference_no = (pe.get("reference_no") or "").strip()
        item.chequereference_date = pe.get("reference_date") or None

    else:
        item.chequereference_no = ""
        item.chequereference_date = None

for item in doc.advances:
    if item.reference_type == "Payment Entry" and item.reference_name:
        pe = frappe.db.get_value(
            "Payment Entry",
            item.reference_name,
            ["reference_no", "reference_date"],
            as_dict=True
        ) or {}

        item.chequereference_no = (pe.get("reference_no") or "").strip()
        item.chequereference_date = pe.get("reference_date") or None

    else:
        item.chequereference_no = ""
        item.chequereference_date = None

if not doc.get("accept"):
    frappe.throw(
        _("By continuing, you must accept the Terms and Conditions.")
    )

# Clear previous assignments
frappe.desk.form.assign_to.clear(
    doctype=doc.doctype,
    name=doc.name
)

assigned_users = []

# Loop through multi select employee table
for row in doc.employee:   # <-- replace 'employee' with your actual table fieldname if different

    if row.employee:
        user_id = frappe.db.get_value("Employee", row.employee, "user_id")

        if user_id:
            assigned_users.append(user_id)

# Assign to all linked users
if assigned_users:
    frappe.desk.form.assign_to.add(
        {
            "assign_to": assigned_users,
            "doctype": doc.doctype,
            "name": doc.name,
            "description": "Auto-assigned based on Employees selected"
        }
    )

gross_words = frappe.call(
	"mohan_impex.amount_in_word.weight_in_words",
	amount=doc.gross_weight or 0
) or ""

net_words = frappe.call(
	"mohan_impex.amount_in_word.weight_in_words",
	amount=doc.net_weight_pkg or 0
) or ""

updates = {}

if (doc.get("total_gross_weight") or "") != gross_words:
	updates["total_gross_weight"] = gross_words

if (doc.get("net_weight") or "") != net_words:
	updates["net_weight"] = net_words

if updates:
	frappe.db.set_value("Packing Slip", doc.name, updates, update_modified=False)
